File: platform/plugin-sdk/src/log.ts, lines 58-73

The issue: safeSerializeArg has top-level handling for DOM nodes (line 46), functions (line 41), symbols (line 42), and bigints (line 43). But the JSON.stringify replacer function (lines 60-68) only handles functions (line 65), bigints (line 66), and symbols (line 67) — it does NOT handle DOM nodes. When an object's property value is a DOM node, the replacer tries to stringify it as a plain object, which recursively traverses the entire DOM subtree before either producing a massive string or hitting a circular reference or error.

Fix: Add DOM node detection in the replacer function, between the circular-reference check and the function check:
```typescript
const json = JSON.stringify(value, (_key, v: unknown) => {
  if (typeof v === 'object' && v !== null) {
    if (seen.has(v)) return '[Circular]';
    seen.add(v);
    // DOM node check — must come after circular ref check
    if (typeof (v as { nodeType?: unknown }).nodeType === 'number') {
      const node = v as { nodeName?: string; id?: string; className?: string };
      const className = node.className ? `.${node.className.split(' ')[0] ?? ''}` : '';
      return `[${node.nodeName ?? 'Node'}${node.id ? `#${node.id}` : ''}${className}]`;
    }
  }
  if (typeof v === 'function') return `[Function: ${(v as { name?: string }).name || 'anonymous'}]`;
  if (typeof v === 'bigint') return `[BigInt: ${v.toString()}]`;
  if (typeof v === 'symbol') return `[Symbol: ${v.description ?? ''}]`;
  return v;
});
```

